import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    penalty_weight = 1000  # This weight influences how much the penalty for missing a time window is considered

    best_score = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        time_to_customer = travel_time(cur_truck_pos, customer)
        arrival_time = current_time + time_to_customer
        start_window, end_window = time_windows[i]

        # Calculate penalty for missing the time window
        if arrival_time > end_window:
            penalty = penalty_weight * (arrival_time - end_window)
        elif arrival_time < start_window:
            penalty = penalty_weight * (start_window - arrival_time)
        else:
            penalty = 0

        total_score = time_to_customer + penalty

        if total_score < best_score:
            best_score = total_score
            best_node = i

    if best_score == float('inf'):
        best_node = None

    return best_node
